SourceCode.Declaration:
/// <summary>
/// Guards inbound SQL service calls by environment pattern.
/// </summary>
public final class SIMSStartSqlExecutionValidator
{
}

Method.Source:
public static str currentEnvironmentFqdn()
{
    var applicationEnvironment = Microsoft.Dynamics.ApplicationPlatform.Environment.EnvironmentFactory::GetApplicationEnvironment();

    return applicationEnvironment.Infrastructure.FullyQualifiedDomainName;
}

/// <summary>
/// Returns empty string if the active host matches the configured pattern; otherwise an error message label or formatted text.
/// </summary>
public static str validateEnvironmentMessage(SIMSStartParameters _serviceParameters)
{
    str envUrl = SIMSStartSqlExecutionValidator::currentEnvironmentFqdn();
    str pattern = strLRTrim(_serviceParameters.AllowedServiceEnvironmentPattern);

    if (!strLen(pattern))
    {
        return "@SIMSStartProcessing:SqlExecServiceEnvPatternMissing";
    }

    if (!(envUrl like pattern))
    {
        return strFmt("@SIMSStartProcessing:SqlExecServiceEnvMismatch", envUrl, pattern);
    }

    return '';
}

/// <summary>
/// Validates a startup-table line for catalog SQL execution via the service.
/// </summary>
public static str validateCatalogLine(SIMSStartTable _line)
{
    if (!_line.RecId)
    {
        return "@SIMSStartProcessing:SqlExecServiceLineNotFound";
    }

    if (_line.TaskType != SIMSStartTaskType::SQL)
    {
        return "@SIMSStartProcessing:SqlExecServiceLineNotSql";
    }

    if (!_line.checkIfLineCanRun())
    {
        return "@SIMSStartProcessing:SqlExecServiceLineNotRunnable";
    }

    return '';
}
